function claim(policy, incident) {
  let payout = 0;
  for (const damage of incident.damages) {
    payout += Math.max(0, damage.amount - 100);
  }
  payout = Math.min(payout, policy.remainingCap);
  return { payout, remainingCap: policy.remainingCap - payout };
